import { BrowserRouter, Routes, Route, Link, useNavigate } from "react-router-dom";
import { Container, Navbar, Nav, Button } from "react-bootstrap"; // Import từ React-Bootstrap
import { useState, useEffect } from "react";

import LoginPage from "./pages/LoginPage";
import RegisterPage from "./pages/RegisterPage";
import HomePage from "./pages/HomePage"; // Trang chủ sau khi đăng nhập thành công

function App() {
  const [user, setUser] = useState(null);

  useEffect(() => {
    const storedUser = localStorage.getItem("user");
    if (storedUser) {
      setUser(JSON.parse(storedUser));
    }
  }, []);

  return (
    <BrowserRouter>
      <div style={{ fontFamily: "Arial" }}>
        {/* Navbar */}
        <Navbar bg="dark" variant="dark" expand="lg" className="mb-4">
          <Container>
            <Navbar.Brand as={Link} to="/">Concert Ticket</Navbar.Brand>
            <Nav className="ms-auto">
              {user ? (
                <>
                  <Nav.Link as={Link} to="/home">Trang chủ</Nav.Link>
                  <Button variant="outline-light" onClick={() => {
                    localStorage.removeItem("token");
                    localStorage.removeItem("user");
                    setUser(null);
                    navigate("/login");
                  }}>
                    Đăng xuất
                  </Button>
                </>
              ) : (
                <Nav.Link as={Link} to="/register">Đăng ký</Nav.Link>
              )}
            </Nav>
          </Container>
        </Navbar>

        {/* Nội dung chính */}
        <Container>
          <Routes>
            <Route path="/home" element={user ? <HomePage user={user} /> : <LoginPage />} />
            <Route path="/login" element={<LoginPage />} />
            <Route path="/register" element={<RegisterPage />} />
            <Route path="*" element={<LoginPage />} />
          </Routes>
        </Container>
      </div>
    </BrowserRouter>
  );
}

export default App;
